#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100005

struct Pair {
    int height;
    int color;
};

int compare(const void *a, const void *b) {
    struct Pair *p1 = (struct Pair *)a;
    struct Pair *p2 = (struct Pair *)b;
    return p2->height - p1->height;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        struct Pair pairs[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &pairs[i].height);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &pairs[i].color);
        }
        qsort(pairs, N, sizeof(struct Pair), compare);
        int max_height = 0;
        int distinct_colors = 0;
        int colors[N];
        memset(colors, 0, sizeof(colors));
        for (int i = 0; i < N; i++) {
            if (pairs[i].height > max_height) {
                if (!colors[pairs[i].color - 1]) {
                    distinct_colors++;
                    colors[pairs[i].color - 1] = 1;
                }
                max_height = pairs[i].height;
            }
        }
        printf("%d\n", distinct_colors);
    }
    return 0;
}

