import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Pair implements Comparable<Pair> {
        int height;
        int color;

        public Pair(int height, int color) {
            this.height = height;
            this.color = color;
        }

        @Override
        public int compareTo(Pair o) {
            return o.height - this.height;
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();
            Pair[] pairs = new Pair[N];
            for (int i = 0; i < N; i++) {
                int height = scanner.nextInt();
                pairs[i] = new Pair(height, 0);
            }
            for (int i = 0; i < N; i++) {
                pairs[i].color = scanner.nextInt();
            }
            Arrays.sort(pairs);
            int max_height = 0;
            int distinct_colors = 0;
            boolean[] colors = new boolean[M];
            for (int i = 0; i < N; i++) {
                if (pairs[i].height > max_height) {
                    if (!colors[pairs[i].color - 1]) {
                        distinct_colors++;
                        colors[pairs[i].color - 1] = true;
                    }
                    max_height = pairs[i].height;
                }
            }
            System.out.println(distinct_colors);
        }
    }
}

