const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextLine() {
    return lines[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextInts() {
    return nextLine().split(' ').map(Number);
}

let T = nextInt();
while (T-- > 0) {
    let [N, M] = nextInts();
    let heights = nextInts();
    let colors = nextInts();
    let pairs = heights.map((height, i) => [height, colors[i]]);
    pairs.sort((a, b) => b[0] - a[0]);
    let max_height = 0;
    let distinct_colors = 0;
    let seen_colors = new Set();
    for (let [height, color] of pairs) {
        if (height > max_height) {
            if (!seen_colors.has(color)) {
                distinct_colors++;
                seen_colors.add(color);
            }
            max_height = height;
        }
    }
    console.log(distinct_colors);
}
